    n = max(1, min(size, 99))
    if rng.random() < 0.5:
        arr = list(range(1, n)) + [n, n]
        rng.shuffle(arr)
    else:
        length = n + 1
        arr = [rng.randint(1, 200) for _ in range(length)]
    return [arr]

