from collections import Counter

class Solution:
    def isGood(self, nums):
        n = len(nums) - 1
        if n < 1:
            return False
        c = Counter(nums)
        if c.get(n, 0) != 2:
            return False
        for v in range(1, n):
            if c.get(v, 0) != 1:
                return False
        return sum(c.values()) == len(nums)

